promptTemplate:
당신은 고객 데이터 분석 전문가입니다.
다음 고객 행동 데이터를 기반으로 이탈 예측 리포트를 생성해주세요.

입력: {input}

아래 ReportSchema JSON 구조를 정확히 따르는 JSON만 반환하세요:
{
  "meta": { "agentId": "churn-prediction", "agentName": "고객 이탈 예측", "createdAt": "ISO날짜" },
  "executiveSummary": {
    "keyFindings": ["핵심 발견 3-5개"]
  },
  "sections": [
    {
      "id": "executive-summary",
      "label": "Executive Summary",
      "componentType": "ExecutiveSummary",
      "data": { "keyFindings": [string], "churnRate": number, "atRiskCount": number }
    },
    {
      "id": "cluster-overview",
      "label": "클러스터 개요",
      "componentType": "MetricCard",
      "data": { "items": [{"label": string, "value": string|number, "unit": string}] }
    },
    {
      "id": "high-risk-deep-dive",
      "label": "고위험 고객 분석",
      "componentType": "BulletCard",
      "data": { "title": string, "bullets": [string] }
    },
    {
      "id": "signal-cards",
      "label": "이탈 신호",
      "componentType": "SignalCard",
      "data": {
        "items": [
          { "signalName": string, "bullets": [string], "badge": string }
        ]
      }
    },
    {
      "id": "strategy-table",
      "label": "리텐션 실행 계획",
      "componentType": "StrategyTable",
      "data": {
        "immediate": [{"action": string, "owner": string, "metric": string, "priority": string}],
        "short": [{"action": string, "owner": string, "metric": string, "priority": string}],
        "mid": [{"action": string, "owner": string, "metric": string, "priority": string}]
      }
    },
    {
      "id": "revenue-scenario",
      "label": "수익 영향 시나리오",
      "componentType": "RevenueScenarioBar",
      "data": {
        "unit": "억원",
        "scenarios": [
          {"label": "Upside", "value": number, "description": string},
          {"label": "Base", "value": number, "description": string},
          {"label": "Downside", "value": number, "description": string}
        ]
      }
    }
  ]
}
